#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_set_and_get() {
        let mut bs = BitSet::new(128);
        bs.set(0);
        bs.set(5);
        bs.set(127);
        assert!(bs.get(0));
        assert!(bs.get(5));
        assert!(bs.get(127));
        assert!(!bs.get(1));
    }

    #[test]
    fn test_clear() {
        let mut bs = BitSet::new(64);
        bs.set(10);
        assert!(bs.get(10));
        bs.clear(10);
        assert!(!bs.get(10));
    }

    #[test]
    fn test_toggle() {
        let mut bs = BitSet::new(64);
        bs.toggle(7);
        assert!(bs.get(7));
        bs.toggle(7);
        assert!(!bs.get(7));
    }

    #[test]
    fn test_count_ones() {
        let mut bs = BitSet::new(256);
        bs.set(0);
        bs.set(63);
        bs.set(64);
        bs.set(200);
        assert_eq!(bs.count_ones(), 4);
    }

    #[test]
    fn test_cross_word_boundary() {
        let mut bs = BitSet::new(128);
        for i in 60..68 {
            bs.set(i);
        }
        assert_eq!(bs.count_ones(), 8);
        for i in 60..68 {
            assert!(bs.get(i));
        }
    }

    #[test]
    fn test_new_all_zero() {
        let bs = BitSet::new(100);
        assert_eq!(bs.count_ones(), 0);
        for i in 0..100 {
            assert!(!bs.get(i));
        }
    }
}
